  "l2_points": [
    {
      "id": "l2_convex_set",
      "name": "凸集",
      "level": "L2",
      "description": "向量空间中的一个集合，如果对于任意两点a和b属于该集合，连接a和b的线段也完全位于该集合内，则称该集合为凸集。数学上表示为：对所有λ∈[0,1]，有λa+(1−λ)b∈X。",
      "difficulty": "基础",
      "aliases": ["convex set", "凸集合"]
    },
    {
      "id": "l2_convex_function",
      "name": "凸函数",
      "level": "L2",
      "description": "定义在凸集上的函数f，若对任意x,x'∈X和λ∈[0,1]，满足λf(x)+(1−λ)f(x')≥f(λx+(1−λ)x')，则称f为凸函数。",
      "difficulty": "中等",
      "aliases": ["convex function", "凸性函数"]
    },
    {
      "id": "l2_jensens_inequality",
      "name": "詹森不等式",
      "level": "L2",
      "description": "对于凸函数f，有∑α_i f(x_i) ≥ f(∑α_i x_i)，其中α_i为非负实数且∑α_i=1；或E_X[f(X)] ≥ f(E_X[X])，即凸函数的期望不小于期望的凸函数。",
      "difficulty": "中等",
      "aliases": ["Jensen's inequality", "琴生不等式"]
